+        .collect::<Vec<_>>();
+    weighted_summary(&weighted)
+}
+
+fn throughput_outcome_summary(records: &[Value]) -> Value {
+    let weighted = records
+        .iter()
+        .filter_map(|record| {
+            json_number_as_f64(record.get("calls_per_sec")).map(|throughput| {
+                let weight = record_weight(record);
+                (throughput, weight)
+            })
+        })
+        .collect::<Vec<_>>();
+    weighted_summary(&weighted)
+}
