+fn stage_probe_cost_ms(stage: &str, pmu_multiplier: f64) -> f64 {
+    let base = match stage {
+        "queue" => 42.0,
+        "schedule" => 36.0,
+        "execute" => 34.0,
+        "policy" => 24.0,
+        "io" => 28.0,
+        "marshal" => 18.0,
+        _ => 22.0,
+    };
+    let pressure_factor = (1.0 + ((pmu_multiplier - 1.0).max(0.0) * 0.5)).clamp(0.8, 2.0);
+    base * pressure_factor
+}
